import android.annotation.SuppressLint import androidx.compose.foundation.Canvas import androidx.compose.foundation.background import androidx.compose.foundation.layout.* import androidx.compose.foundation.shape.RoundedCornerShape import androidx.compose.material3.Text import androidx.compose.runtime.Composable import androidx.compose.ui.Alignment import androidx.compose.ui.Modifier import androidx.compose.ui.geometry.Rect import androidx.compose.ui.geometry.Size import androidx.compose.ui.graphics.Color import androidx.compose.ui.graphics.StrokeCap import androidx.compose.ui.graphics.drawscope.Stroke import androidx.compose.ui.platform.LocalDensity import androidx.compose.ui.text.font.FontWeight import androidx.compose.ui.unit.dp import androidx.compose.ui.unit.sp import kotlin.math.min
@SuppressLint("UnusedBoxWithConstraintsScope") @Composable fun CalorieSpeedometer( currentCalories: Int, maxCalories: Int, modifier: Modifier = Modifier ) { val progress = min(currentCalories.toFloat() / maxCalories.toFloat(), 1f) val density = LocalDensity.current
BoxWithConstraints( modifier = modifier .fillMaxWidth() .height(160.dp) // Increased height to fit bigger arcs + text ) { val canvasWidth = constraints.maxWidth.toFloat() val canvasHeight = constraints.maxHeight.toFloat()
// Calculate arc dimensions outside Canvas scope so we can use them later val strokeWidth = with(density) { 32.dp.toPx() } val totalSweep = 180f val gapAngle = 30f // Increased gap for better visibility val segments = 3 val segmentSweep = (totalSweep - gapAngle * (segments - 1)) / segments val startAngle = 180f
// Make the arcs diameter as large as possible within canvas height, but limit by width val maxDiameterByHeight = canvasHeight * 2.2f val maxDiameterByWidth = (canvasWidth * 0.9f) val diameter = min(maxDiameterByHeight, maxDiameterByWidth)
// Calculate bounding rect for arcs val arcLeft = (canvasWidth - diameter) / 2f val arcTop = with(density) { 100.dp.toPx() } - diameter // Position arcs relative to canvas val arcRect = Rect(arcLeft, arcTop, arcLeft + diameter, arcTop + diameter)
Canvas(modifier = Modifier.fillMaxWidth().height(100.dp)) { // Draw background arcs var angle = startAngle repeat(segments) { drawArc( color = Color.LightGray, startAngle = angle, sweepAngle = segmentSweep, useCenter = false, style = Stroke(width = strokeWidth, cap = StrokeCap.Round), topLeft = arcRect.topLeft, size = arcRect.size ) angle += segmentSweep + gapAngle }
// Draw progress arcs val totalProgressSweep = totalSweep * progress var remainingSweep = totalProgressSweep angle = startAngle
repeat(segments) { val sweep = min(segmentSweep, remainingSweep) if (sweep > 0f) { drawArc( color = Color.Black, startAngle = angle, sweepAngle = sweep, useCenter = false, style = Stroke(width = strokeWidth, cap = StrokeCap.Round), topLeft = arcRect.topLeft, size = arcRect.size ) } remainingSweep -= segmentSweep angle += segmentSweep + gapAngle } }
// Text centered below the arcs Column( horizontalAlignment = Alignment.CenterHorizontally, modifier = Modifier .fillMaxWidth() .offset(y = (-124).dp) ) { Text( text = "${maxCalories - currentCalories}", fontSize = 32.sp, color = Color.Black, fontWeight = FontWeight.Bold ) Text( text = "Total calories left", fontSize = 14.sp, color = Color.Gray ) } } }

